# Functional tests for the Quality Playbook specification and validation script.
# These tests verify behavioral requirements derived from SKILL.md and quality_gate.sh.
#
# Usage: bash quality/test_functional.sh
#   or:  bash quality/test_functional.sh <test_name>

set -uo pipefail

SCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"
PROJECT_ROOT="$(cd "${SCRIPT_DIR}/.." && pwd)"
SKILL="${PROJECT_ROOT}/SKILL.md"
GATE="${PROJECT_ROOT}/quality_gate.sh"
PASS=0
FAIL=0
SKIP=0
RUN_FILTER="${1:-}"

pass() { PASS=$((PASS + 1)); echo "  PASS: $1"; }
fail() { FAIL=$((FAIL + 1)); echo "  FAIL: $1"; }
skip() { SKIP=$((SKIP + 1)); echo "  SKIP: $1"; }

should_run() {
    [ -z "$RUN_FILTER" ] || [ "$RUN_FILTER" = "$1" ]
}

# ============================================================================
# Group 1: Spec Requirements
# ============================================================================

echo "=== Spec Requirements ==="

# [Req: formal — REQ-001] tdd-results.json summary key consistency
test_req001_summary_key_consistency() {
    echo "[REQ-001] Summary key 'verified' vs 'tdd_verified' consistency"
    local tdd_verified_count verified_count
    # Count occurrences of tdd_verified in JSON example blocks
    tdd_verified_count=$(grep -c '"tdd_verified"' "$SKILL" 2>/dev/null || echo 0)
    verified_count=$(grep -c '"verified"' "$SKILL" 2>/dev/null || echo 0)

    # The normative text at line 1394 says 'verified' is canonical.
    # Example 1 uses 'tdd_verified' — this is the bug.
    if [ "$tdd_verified_count" -gt 0 ]; then
        fail "SKILL.md contains $tdd_verified_count occurrence(s) of 'tdd_verified' — should be 'verified' per normative text (line 1394)"
    else
        pass "No 'tdd_verified' in SKILL.md — consistent with normative text"
    fi
}

# [Req: formal — REQ-001] quality_gate.sh validates total and verified summary keys
test_req001_gate_validates_summary_keys() {
    echo "[REQ-001] quality_gate.sh validates 'total' and 'verified' summary keys"
    local checks_total checks_verified
    checks_total=$(grep -c '"total"' "$GATE" 2>/dev/null || echo 0)
    checks_verified=$(grep -cE '"verified"' "$GATE" 2>/dev/null || echo 0)

    # The gate should check for 'total' and 'verified' in the summary validation
    # Currently it only checks confirmed_open, red_failed, green_failed
    if grep -q 'for skey in.*total' "$GATE" 2>/dev/null; then
        pass "quality_gate.sh checks for 'total' summary key"
    else
        fail "quality_gate.sh does not check for 'total' summary key"
    fi
    if grep -q 'for skey in.*verified' "$GATE" 2>/dev/null; then
        pass "quality_gate.sh checks for 'verified' summary key"
    else
        fail "quality_gate.sh does not check for 'verified' summary key"
    fi
}

# [Req: formal — REQ-002] Phase numbering consistency
test_req002_phase_numbering() {
    echo "[REQ-002] Phase 7 in plan overview"
    local plan_overview_has_phase7
    # Plan overview is lines 12-31. Check if Phase 7 is mentioned there.
    plan_overview_has_phase7=$(sed -n '12,31p' "$SKILL" | grep -ci 'phase 7' | head -1 || echo 0)
    local body_has_phase7
    body_has_phase7=$(grep -c '## Phase 7' "$SKILL" 2>/dev/null || echo 0)

    if [ "$body_has_phase7" -gt 0 ] && [ "$plan_overview_has_phase7" -eq 0 ]; then
        fail "Phase 7 exists in SKILL.md body but NOT in plan overview (lines 12-31)"
    elif [ "$body_has_phase7" -gt 0 ] && [ "$plan_overview_has_phase7" -gt 0 ]; then
        pass "Phase 7 in body and plan overview are consistent"
    else
        pass "No Phase 7 in body — no inconsistency"
    fi
}

# [Req: formal — REQ-002] Convergence check reference to Phase 7
test_req002_convergence_phase7_ref() {
    echo "[REQ-002] Convergence check 'skip to Phase 7' reference"
    if grep -qi 'skip to Phase 7' "$SKILL" 2>/dev/null; then
        local plan_has_7
        plan_has_7=$(sed -n '12,31p' "$SKILL" | grep -ci 'phase 7' | head -1 || echo 0)
        if [ "$plan_has_7" -eq 0 ]; then
            fail "'skip to Phase 7' reference exists but Phase 7 not in plan overview"
        else
            pass "'skip to Phase 7' reference is consistent with plan overview"
        fi
    else
        pass "No 'skip to Phase 7' reference found"
    fi
}

# [Req: formal — REQ-003] Hardcoded .github/skills/references/ paths
test_req003_hardcoded_paths() {
    echo "[REQ-003] Reference paths must not be hardcoded to .github/skills/references/"
    local hardcoded_count
    hardcoded_count=$(grep -c '\.github/skills/references/' "$SKILL" 2>/dev/null || echo 0)
    if [ "$hardcoded_count" -gt 0 ]; then
        fail "SKILL.md has $hardcoded_count hardcoded .github/skills/references/ path(s) — breaks Claude Code installations"
    else
        pass "No hardcoded .github/skills/references/ paths in SKILL.md"
    fi
}

# [Req: formal — REQ-004] quality_gate.sh validates TDD log status tags
test_req004_tdd_log_status_tags() {
    echo "[REQ-004] quality_gate.sh validates TDD log status tags (RED/GREEN/NOT_RUN/ERROR)"
    # SKILL.md line 1137 claims the gate checks for status tag presence
    local claim_exists gate_reads_tag
    claim_exists=$(grep -c 'quality_gate.sh will check for its presence' "$SKILL" 2>/dev/null || echo 0)
    # Check if quality_gate.sh actually reads the first line of log files
    gate_reads_tag=$(grep -cE 'head -1|sed -n 1p|read.*log|RED|GREEN|NOT_RUN|ERROR' "$GATE" 2>/dev/null || echo 0)

    if [ "$claim_exists" -gt 0 ] && [ "$gate_reads_tag" -eq 0 ]; then
        fail "SKILL.md claims gate checks TDD log status tags, but quality_gate.sh only checks file existence"
    elif [ "$claim_exists" -gt 0 ] && [ "$gate_reads_tag" -gt 0 ]; then
        pass "SKILL.md claim and quality_gate.sh validation are consistent"
    else
        pass "No inconsistency (claim not found or gate validates)"
    fi
}

# [Req: formal — REQ-005] File existence checks cover required artifacts
test_req005_file_existence_contracts() {
    echo "[REQ-005] quality_gate.sh checks for CONTRACTS.md"
    if grep -q 'CONTRACTS.md' "$GATE" 2>/dev/null; then
        pass "quality_gate.sh checks for CONTRACTS.md"
    else
        fail "quality_gate.sh does NOT check for CONTRACTS.md (marked Required in artifact table)"
    fi
}

test_req005_file_existence_exploration() {
    echo "[REQ-005] quality_gate.sh checks for EXPLORATION.md"
    if grep -q 'EXPLORATION.md' "$GATE" 2>/dev/null; then
        pass "quality_gate.sh checks for EXPLORATION.md"
    else
        fail "quality_gate.sh does NOT check for EXPLORATION.md"
    fi
}

test_req005_file_existence_run_protocols() {
    echo "[REQ-005] quality_gate.sh checks for RUN_*.md protocol files"
    local missing=0
    for f in RUN_CODE_REVIEW.md RUN_INTEGRATION_TESTS.md RUN_SPEC_AUDIT.md RUN_TDD_TESTS.md; do
        if ! grep -q "$f" "$GATE" 2>/dev/null; then
            fail "quality_gate.sh does NOT check for $f (marked Required)"
            missing=$((missing + 1))
        fi
    done
    [ "$missing" -eq 0 ] && pass "quality_gate.sh checks for all RUN_*.md files"
}

# [Req: formal — REQ-006] DEVELOPMENT_CONTEXT.md Phase 3 mislabel
test_req006_dev_context_phase_label() {
