    local dev_ctx="${PROJECT_ROOT}/ai_context/DEVELOPMENT_CONTEXT.md"
    if [ -f "$dev_ctx" ]; then
        if grep -q 'verification.md.*Phase 3' "$dev_ctx" 2>/dev/null; then
            fail "DEVELOPMENT_CONTEXT.md labels verification.md as Phase 3 (should be Phase 6)"
        else
