# [Req: formal — REQ-008] Artifact table Created In for verify.sh
test_req008_verify_created_in() {
    echo "[REQ-008] Artifact table 'Created In' for verify.sh"
    # Check whether the artifact table says verify.sh is Phase 5
    # AND whether the instructions say to create it in Phase 2
    local table_phase
    table_phase=$(grep -A1 'verify.sh\|mechanical.*verify' "$SKILL" 2>/dev/null | grep -oE 'Phase [0-9]+' | head -1 || echo "")
    local instruction_phase
    instruction_phase=$(grep -B5 'verify.sh' "$SKILL" 2>/dev/null | grep -oE 'Phase [0-9]+[ab]*' | head -1 || echo "")

    if echo "$table_phase" | grep -q 'Phase 5' && echo "$instruction_phase" | grep -qi 'Phase 2'; then
        fail "Artifact table says verify.sh is 'Phase 5' but instructions create it in Phase 2"
    else
        pass "verify.sh Created In column is consistent with instructions (or cannot determine)"
    fi
}

# [Req: formal — REQ-011] TOOLKIT.md installation paths
test_req011_toolkit_both_paths() {
    echo "[REQ-011] TOOLKIT.md documents both installation paths"
    local toolkit="${PROJECT_ROOT}/ai_context/TOOLKIT.md"
    if [ -f "$toolkit" ]; then
        local has_github has_claude
        has_github=$(grep -c '.github/skills' "$toolkit" 2>/dev/null || echo 0)
        has_claude=$(grep -c '.claude/skills' "$toolkit" 2>/dev/null || echo 0)
        if [ "$has_github" -gt 0 ] && [ "$has_claude" -gt 0 ]; then
            pass "TOOLKIT.md shows both .github/skills/ and .claude/skills/ paths"
        elif [ "$has_github" -gt 0 ] && [ "$has_claude" -eq 0 ]; then
            fail "TOOLKIT.md only shows .github/skills/ path — missing Claude Code installation"
        else
            fail "TOOLKIT.md missing expected installation paths"
        fi
    else
        skip "TOOLKIT.md not found"
    fi
}

# [Req: formal — REQ-012] Per-bug field classification
test_req012_perbug_field_classification() {
    echo "[REQ-012] SKILL.md classifies additional per-bug fields as required or optional"
    # Check if SKILL.md explicitly marks the additional fields (regression_patch, fix_patch,
    # patch_gate_passed, junit_red, junit_green, junit_available, notes)
    local has_classification
    has_classification=$(grep -cE '(optional|required).*per-bug|per-bug.*(optional|required)' "$SKILL" 2>/dev/null || echo 0)
    # The normative text at line 1392 lists 7 required fields.
    # Example 2 has 14 fields. The extra 7 are not classified.
    local extra_fields_documented
    extra_fields_documented=$(grep -c 'regression_patch.*optional\|notes.*optional\|junit_.*optional' "$SKILL" 2>/dev/null || echo 0)
    if [ "$extra_fields_documented" -gt 0 ]; then
        pass "Additional per-bug fields are classified in SKILL.md"
    else
        fail "Additional per-bug fields in Example 2 are not classified as required or optional"
    fi
}

