# Scenario 3: Gate under-validation
test_scenario3_gate_undervalidation() {
    echo "[Scenario 3] quality_gate.sh checks all Required artifacts"
    # Count Required artifacts from SKILL.md artifact table (approximation)
    local required_in_table checked_by_gate
    required_in_table=0
    checked_by_gate=0
    for artifact in QUALITY.md REQUIREMENTS.md CONTRACTS.md COVERAGE_MATRIX.md COMPLETENESS_REPORT.md PROGRESS.md BUGS.md; do
        required_in_table=$((required_in_table + 1))
        if grep -q "\"$artifact\"" "$GATE" 2>/dev/null || grep -q "'$artifact'" "$GATE" 2>/dev/null || grep -q "$artifact" "$GATE" 2>/dev/null; then
            checked_by_gate=$((checked_by_gate + 1))
        fi
    done
    if [ "$checked_by_gate" -lt "$required_in_table" ]; then
        fail "Gate checks $checked_by_gate of $required_in_table required core artifacts"
    else
        pass "Gate checks all $required_in_table required core artifacts"
    fi
}

# Scenario 4: Phase 7 unreachable
test_scenario4_phase7_unreachable() {
    echo "[Scenario 4] Phase 7 reachability"
    local phase7_defined plan_overview_mentions end_of_6_mentions
    phase7_defined=$(grep -c '## Phase 7' "$SKILL" 2>/dev/null || echo 0)
    plan_overview_mentions=$(sed -n '12,31p' "$SKILL" | grep -ci 'phase 7' | head -1 || echo 0)
    end_of_6_mentions=$(grep -A20 'Phase 6 Complete' "$SKILL" 2>/dev/null | grep -ci 'phase 7' | head -1 || echo 0)

    if [ "$phase7_defined" -gt 0 ] && [ "$plan_overview_mentions" -eq 0 ] && [ "$end_of_6_mentions" -eq 0 ]; then
        fail "Phase 7 defined but unreachable — not in plan overview or end-of-Phase-6 message"
    else
        pass "Phase 7 reachability is consistent"
    fi
}

