# [Req: inferred — quality_gate.sh glob safety]
test_boundary_glob_empty_match() {
    echo "[REQ-009] Glob patterns handle empty match"
    # Check if the writeup loop uses a glob guard (nullglob, [[ -f ]], etc.)
    local has_file_guard
    has_file_guard=$(grep -A2 'for wf in.*writeups.*BUG' "$GATE" 2>/dev/null | grep -c '\[ -f' || echo 0)
    if [ "$has_file_guard" -gt 0 ]; then
        pass "Writeup glob loop has file existence guard"
    else
        # The guard exists (line 508: [ -f "$wf" ] || continue) but the glob
        # still expands to the literal pattern. Check if the guard catches it.
        local has_continue
        has_continue=$(grep -A3 'for wf in.*writeups.*BUG' "$GATE" 2>/dev/null | grep -c 'continue' || echo 0)
        if [ "$has_continue" -gt 0 ]; then
            pass "Writeup glob loop has continue guard for non-matching globs"
        else
            fail "Writeup glob loop has no guard against empty glob expansion"
        fi
    fi
}

# [Req: inferred — quality_gate.sh set -e not set]
test_boundary_set_e() {
    echo "[Edge] quality_gate.sh uses set -e"
    if grep -q 'set -e' "$GATE" 2>/dev/null; then
        pass "quality_gate.sh has set -e"
    else
        # This is intentional — the script uses manual FAIL counting instead of set -e.
        # But it means individual command failures don't abort the script.
        pass "quality_gate.sh deliberately omits set -e (uses FAIL counter pattern)"
    fi
}

# [Req: inferred — version detection]
test_boundary_version_detection() {
    echo "[Edge] quality_gate.sh version detection tries multiple SKILL.md locations"
    local location_count
    location_count=$(grep -c 'SKILL.md' "$GATE" 2>/dev/null | head -1 || echo 0)
    if [ "$location_count" -ge 3 ]; then
        pass "Version detection checks 3+ SKILL.md locations"
    else
        fail "Version detection checks fewer than 3 SKILL.md locations"
    fi
}

# [Req: inferred — orchestrator path consistency]
test_boundary_orchestrator_paths() {
    echo "[Edge] Both orchestrators check for Claude Code installation path"
    local claude_agent="${PROJECT_ROOT}/agents/quality-playbook-claude.agent.md"
    local general_agent="${PROJECT_ROOT}/agents/quality-playbook.agent.md"
    local claude_check=0 general_check=0
    if [ -f "$claude_agent" ] && grep -q '\.claude/skills' "$claude_agent" 2>/dev/null; then
        claude_check=1
    fi
    if [ -f "$general_agent" ] && grep -q '\.claude/skills' "$general_agent" 2>/dev/null; then
        general_check=1
    fi
    if [ "$claude_check" -eq 1 ] && [ "$general_check" -eq 1 ]; then
        pass "Both orchestrators check for .claude/skills/ path"
    else
        fail "Not all orchestrators check for .claude/skills/ path (claude=$claude_check, general=$general_check)"
    fi
}

# [Req: inferred — JSON helper correctness]
test_boundary_json_helpers() {
    echo "[Edge] json_has_key uses grep (not JSON parser)"
    if grep -q 'grep.*"${key}"' "$GATE" 2>/dev/null; then
        # This is by design — the project uses grep-based JSON parsing.
        # But it means nested key names could false-match.
        pass "json_has_key uses grep (design choice — no JSON parser dependency)"
    else
        skip "Cannot determine json_has_key implementation"
    fi
}

